const body = $json.body ?? {};
const errors = [];

const caravana = String(body.caravana ?? '').trim().toUpperCase();
const fechaTacto = String(body.fecha_tacto ?? body.fecha ?? '').trim();
const resultadoRaw = String(body.resultado ?? '')
  .trim()
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');
const observaciones = String(body.observaciones ?? '').trim();

if (!caravana) errors.push('caravana es obligatoria');

const dateMatch = /^(\d{4})-(\d{2})-(\d{2})$/.exec(fechaTacto);
let validDate = false;
if (dateMatch) {
  const year = Number(dateMatch[1]);
  const month = Number(dateMatch[2]);
  const day = Number(dateMatch[3]);
  const parsed = new Date(Date.UTC(year, month - 1, day));
  validDate =
    parsed.getUTCFullYear() === year &&
    parsed.getUTCMonth() === month - 1 &&
    parsed.getUTCDate() === day;
}
if (!validDate) errors.push('fecha debe ser una fecha válida con formato YYYY-MM-DD');

const allowedResults = ['positivo', 'negativo'];
if (!allowedResults.includes(resultadoRaw)) {
  errors.push('resultado debe ser positivo o negativo');
}

const daysRaw = body.dias_gestacion_estimados ?? body.dias_gestacion;
let diasGestacion = '';
if (resultadoRaw === 'positivo') {
  const parsedDays = Number(daysRaw);
  if (
    daysRaw === undefined ||
    daysRaw === null ||
    daysRaw === '' ||
    !Number.isInteger(parsedDays) ||
    parsedDays < 0 ||
    parsedDays > 283
  ) {
    errors.push('días de gestación debe ser un entero entre 0 y 283 para un resultado positivo');
  } else {
    diasGestacion = parsedDays;
  }
}

return [{
  json: {
    estado_validacion: errors.length === 0 ? 'valido' : 'invalido',
    error: errors.join('; '),
    caravana,
    fecha_tacto: fechaTacto,
    resultado: resultadoRaw,
    dias_gestacion_estimados: diasGestacion,
    observaciones,
  },
}];

const entrada = $('Validar Entrada').first().json;

let fechaProbableParto = '';
if (entrada.resultado === 'positivo') {
  const fecha = new Date(entrada.fecha_tacto + 'T00:00:00.000Z');
  fecha.setUTCDate(fecha.getUTCDate() + (283 - entrada.dias_gestacion_estimados));
  fechaProbableParto = fecha.toISOString().slice(0, 10);
}

return [{
  json: {
    id_tacto: 'T-' + Date.now(),
    caravana: entrada.caravana,
    fecha_tacto: entrada.fecha_tacto,
    resultado: entrada.resultado,
    dias_gestacion_estimados: entrada.dias_gestacion_estimados,
    fecha_probable_parto: fechaProbableParto,
    observaciones: entrada.observaciones,
    creado_en: new Date().toISOString(),
  },
}];
